  8→/// Generate `all_tool_schemas()` from a declarative tool list.
  9→/// Each entry: name, description, schema (serde_json::Value).
 10→macro_rules! tools {
 11→    ( $( $name:expr, $desc:expr, $schema:expr );+ $(;)? ) => {
 12→        pub fn all_tool_schemas() -> Vec<serde_json::Value> {
 13→            vec![
 14→                $(
 15→                    serde_json::json!({
 16→                        "name": $name,
 17→                        "description": $desc,
 18→                        "input_schema": $schema,
 19→                    }),
 20→                )+
 21→            ]
 22→        }
 23→    };
 24→}
 25→
 26→tools! {
 27→    "Read", "Read a file from disk. Returns file contents as text. Binary files return a placeholder message. Maximum 1MB file size.",
 28→    json!({
 29→        "type": "object",
 30→        "properties": {
 31→            "file_path": {
 32→                "type": "string",
 33→                "description": "Absolute or relative path to the file to read"
 34→            }
 35→        },
 36→        "required": ["file_path"]
 37→    });
 38→
 39→    "Glob", "List files matching a glob pattern. Returns up to 1000 entries sorted by modification time.",
 40→    json!({
 41→        "type": "object",
 42→        "properties": {
 43→            "pattern": {
 44→                "type": "string",
 45→                "description": "Glob pattern (e.g. '**/*.rs', 'src/*.ts')"
 46→            },
 47→            "path": {
 48→                "type": "string",
 49→                "description": "Base directory to search from (default: current directory)"
 50→            }
 51→        },
 52→        "required": ["pattern"]
 53→    });
 54→
 55→    "Bash", "Execute a bash command. Returns stdout and stderr. 120 second timeout. Streaming output.",
 56→    json!({
 57→        "type": "object",
 58→        "properties": {
 59→            "command": {
 60→                "type": "string",
 61→                "description": "The bash command to execute"
 62→            },
 63→            "description": {
 64→                "type": "string",
 65→                "description": "Brief description of what the command does"
 66→            }
 67→        },
 68→        "required": ["command"]
 69→    });
 70→
 71→    "Edit", "Edit a file by replacing exact text matches. Maximum 100KB file size. Default: single exact match. Set replace_all=true for bulk replacements. Empty old_str on missing file creates the file (with parent directories). Empty old_str on existing file appends content.",
 72→    json!({
 73→        "type": "object",
 74→        "properties": {
 75→            "file_path": {
 76→                "type": "string",
 77→                "description": "Path to the file to edit"
 78→            },
 79→            "old_str": {
 80→                "type": "string",
 81→                "description": "Exact text to find and replace (empty string = create/append)"
 82→            },
 83→            "new_str": {
 84→                "type": "string",
 85→                "description": "Replacement text"
 86→            },
 87→            "replace_all": {
 88→                "type": "boolean",
 89→                "description": "Replace all occurrences instead of requiring a single unique match (default: false)"
 90→            }
 91→        },
 92→        "required": ["file_path", "old_str", "new_str"]
 93→    });
 94→
 95→    "Grep", "Search file contents using ripgrep (rg). Returns up to 50 matches. Requires rg to be installed.",
 96→    json!({
 97→        "type": "object",
 98→        "properties": {
 99→            "pattern": {
100→                "type": "string",
101→                "description": "Regex pattern to search for"
102→            },
103→            "path": {
104→                "type": "string",
105→                "description": "File or directory to search in (default: current directory)"
106→            },
107→            "file_type": {
108→                "type": "string",
109→                "description": "File type filter (e.g. 'rs', 'py', 'js')"
110→            },
111→            "case_sensitive": {
