184→fn glob_exec(input: &Value) -> Result<String, String> {
185→    let pattern = input["pattern"]
186→        .as_str()
187→        .ok_or("Missing required parameter: pattern")?;
188→    let base = input["path"].as_str().unwrap_or(".");
189→
190→    // Shell out to find with glob, or use a simpler approach
191→    // Using bash for glob expansion to avoid pulling in the glob crate
192→    let full_pattern = if pattern.starts_with('/') || pattern.starts_with('.') {
193→        pattern.to_string()
194→    } else {
195→        format!("{base}/{pattern}")
196→    };
197→
198→    let output = Command::new("bash")
199→        .arg("-c")
200→        .arg(format!(
201→            "shopt -s globstar nullglob; files=({full_pattern}); printf '%s\\n' \"${{files[@]}}\" | head -1000"
202→        ))
203→        .output()
204→        .map_err(|e| format!("Failed to execute glob: {e}"))?;
205→
206→    let stdout = String::from_utf8_lossy(&output.stdout).to_string();
207→    let result = stdout.trim().to_string();
208→
209→    if result.is_empty() {
210→        Ok("No files found".to_string())
211→    } else {
212→        Ok(result)
213→    }
214→}
