216→/// Deny-list patterns for bash commands. Whitespace-normalized lowercase matching.
217→const BASH_DENY_LIST: &[&str] = &[
218→    "rm -rf /",
219→    "rm -fr /",
220→    "rm -rf /*",
221→    "rm -fr /*",
222→    ":(){ :|:& };:",
223→    "dd if=/dev",
224→    "mkfs",
225→    "chmod 777 /",
226→    "git push --force",
227→    "git push -f",
228→];
229→
230→fn normalize_command(cmd: &str) -> String {
231→    cmd.to_lowercase()
232→        .split_whitespace()
233→        .collect::<Vec<_>>()
234→        .join(" ")
235→}
236→
237→fn is_denied_command(cmd: &str) -> bool {
238→    let normalized = normalize_command(cmd);
239→    BASH_DENY_LIST
240→        .iter()
241→        .any(|pattern| normalized.contains(pattern))
242→}
