244→fn bash_exec(input: &Value, stream_cb: &mut dyn FnMut(&str)) -> Result<String, String> {
245→    let command = input["command"]
246→        .as_str()
247→        .ok_or("Missing required parameter: command")?;
248→
249→    if is_denied_command(command) {
250→        return Err(format!("Command blocked by safety guard: {command}"));
251→    }
252→
253→    let timeout = Duration::from_secs(120);
254→    let deadline = Instant::now() + timeout;
255→
256→    let mut child = Command::new("bash")
257→        .arg("-c")
258→        .arg(command)
259→        .stdout(Stdio::piped())
260→        .stderr(Stdio::piped())
261→        .spawn()
262→        .map_err(|e| format!("Failed to spawn bash: {e}"))?;
263→
264→    let stdout = child.stdout.take().unwrap();
265→    let stderr = child.stderr.take().unwrap();
266→
267→    let (tx_out, rx) = mpsc::channel::<String>();
268→    let tx_err = tx_out.clone();
269→
270→    // Stdout reader thread
271→    std::thread::spawn(move || {
272→        let reader = BufReader::with_capacity(4096, stdout);
273→        let mut buf = Vec::new();
274→        let mut r = reader;
275→        loop {
276→            buf.clear();
277→            match r.read_until(b'\n', &mut buf) {
278→                Ok(0) => break,
279→                Ok(_) => {
280→                    let s = String::from_utf8_lossy(&buf).to_string();
281→                    if tx_out.send(s).is_err() {
282→                        break;
283→                    }
284→                }
285→                Err(_) => break,
286→            }
287→        }
288→    });
289→
290→    // Stderr reader thread
291→    std::thread::spawn(move || {
292→        let reader = BufReader::with_capacity(4096, stderr);
293→        let mut buf = Vec::new();
294→        let mut r = reader;
295→        loop {
296→            buf.clear();
297→            match r.read_until(b'\n', &mut buf) {
298→                Ok(0) => break,
299→                Ok(_) => {
300→                    let s = String::from_utf8_lossy(&buf).to_string();
301→                    if tx_err.send(s).is_err() {
302→                        break;
303→                    }
304→                }
305→                Err(_) => break,
306→            }
307→        }
308→    });
309→
310→    // Drop our copy of tx so rx closes when threads finish
311→    let mut output = String::new();
312→    let mut timed_out = false;
313→
314→    loop {
315→        if Instant::now() >= deadline {
316→            let _ = child.kill();
317→            timed_out = true;
318→            break;
319→        }
320→
321→        match rx.recv_timeout(Duration::from_millis(50)) {
322→            Ok(chunk) => {
323→                stream_cb(&chunk);
324→                output.push_str(&chunk);
325→            }
326→            Err(mpsc::RecvTimeoutError::Timeout) => {
327→                // Check if process has exited
328→                match child.try_wait() {
329→                    Ok(Some(_)) => {
330→                        // Process finished — drain remaining
331→                        while let Ok(chunk) = rx.try_recv() {
332→                            stream_cb(&chunk);
333→                            output.push_str(&chunk);
334→                        }
335→                        break;
336→                    }
337→                    Ok(None) => continue,
338→                    Err(_) => break,
339→                }
340→            }
341→            Err(mpsc::RecvTimeoutError::Disconnected) => {
342→                // Both threads done
343→                let _ = child.wait();
344→                break;
345→            }
346→        }
347→    }
348→
349→    if timed_out {
350→        if output.is_empty() {
351→            return Err(format!("Command timed out after 120s: {command}"));
352→        }
353→        return Err(format!(
354→            "Command timed out after 120s (partial output):\n{output}"
355→        ));
356→    }
357→
358→    let status = child
359→        .wait()
360→        .map_err(|e| format!("Failed to wait for process: {e}"))?;
361→
362→    if status.success() {
363→        Ok(output)
364→    } else {
365→        let code = status.code().unwrap_or(-1);
366→        if output.is_empty() {
367→            Err(format!("Command failed with exit code {code}"))
368→        } else {
369→            Err(format!("Command failed with exit code {code}:\n{output}"))
370→        }
371→    }
372→}
