  78→/// Trim conversation at exchange boundaries to fit within context budget.
  79→/// Preserves the first user message and trims from the front, keeping
  80→/// tool_use/tool_result pairs together.
  81→fn trim_conversation(messages: &mut Vec<Message>) {
  82→    let size: usize = messages
  83→        .iter()
  84→        .map(|m| serde_json::to_string(m).unwrap_or_default().len())
  85→        .sum();
  86→
  87→    if size <= CONTEXT_BUDGET_BYTES || messages.len() <= 2 {
  88→        return;
  89→    }
  90→
  91→    // Keep first message, trim from front of the rest
  92→    let first = messages.remove(0);
  93→    while messages.len() > 1 {
  94→        let new_size: usize = std::iter::once(&first)
  95→            .chain(messages.iter())
  96→            .map(|m| serde_json::to_string(m).unwrap_or_default().len())
  97→            .sum();
  98→        if new_size <= CONTEXT_BUDGET_BYTES {
  99→            break;
 100→        }
 101→        // Remove pairs to maintain alternation
 102→        messages.remove(0);
 103→        if !messages.is_empty() && messages[0].role == "assistant" {
 104→            messages.remove(0);
 105→        }
 106→    }
 107→    messages.insert(0, first);
 108→}
