 263→            io::stderr().flush().ok();
 264→
 265→            let mut input = String::new();
 266→            match io::stdin().lock().read_line(&mut input) {
 267→                Ok(0) => break, // EOF
 268→                Ok(_) => {}
 269→                Err(e) => {
 270→                    eprintln!("Error reading input: {e}");
 271→                    break;
 272→                }
 273→            }
 274→
 275→            let input = input.trim().to_string();
 276→            if input.is_empty() {
 277→                continue;
 278→            }
 279→            if input == "exit" || input == "quit" {
 280→                break;
 281→            }
 282→
 283→            run_turn(
 284→                &cli,
 285→                &client,
 286→                &system_prompt,
 287→                &tools,
 288→                &mut conversation,
 289→                &mut session,
 290→                &hooks,
 291→                &input,
 292→            )
 293→            .await;
 294→        }
 295→    }
 296→
 297→    session.write_context();
 298→}
 299→
 300→#[allow(clippy::too_many_arguments)]
 301→async fn run_turn(
 302→    cli: &Cli,
 303→    client: &AnthropicClient,
 304→    system_prompt: &str,
 305→    tools: &[serde_json::Value],
 306→    conversation: &mut Vec<Message>,
 307→    session: &mut SessionWriter,
 308→    hooks: &HookRunner,
 309→    input: &str,
 310→) {
 311→    // Add user message
 312→    let user_msg = Message {
 313→        role: "user".to_string(),
 314→        content: vec![ContentBlock::Text {
 315→            text: input.to_string(),
 316→        }],
 317→    };
 318→    conversation.push(user_msg.clone());
 319→    session.append_user_turn(&user_msg);
 320→    session.write_prompt(input);
 321→
 322→    let mut tool_iterations: usize = 0;
 323→    let mut continuation_count: usize = 0;
 324→    let mut last_input_tokens: u64 = 0;
 325→    let mut consecutive_block_count: usize = 0;
 326→    let mut total_block_count: usize = 0;
 327→    let mut total_tokens: u64 = 0;
 328→    let mut stop_reason_str = "end_turn";
 329→
 330→    // Inner loop: call API, dispatch tools, repeat
 331→    loop {
 332→        // Token-aware trim: first call (no data) uses byte safety net;
 333→        // subsequent calls skip trim when under threshold.
 334→        trim_if_needed(conversation, last_input_tokens);
 335→
 336→        if tool_iterations >= MAX_TOOL_ITERATIONS {
 337→            eprintln!("[warn] Tool iteration limit ({MAX_TOOL_ITERATIONS}) reached");
 338→            recover_conversation(conversation);
 339→            stop_reason_str = "iteration_limit";
 340→            break;
 341→        }
 342→
 343→        // Retry loop wrapping the API call
 344→        // attempt 0 = initial call, 1..=MAX_RETRIES = retries
 345→        let mut api_result = None;
 346→        #[allow(clippy::needless_range_loop)]
 347→        for attempt in 0..=MAX_RETRIES {
 348→            let result = client
 349→                .send_message(
 350→                    &cli.model,
 351→                    cli.max_tokens,
 352→                    system_prompt,
 353→                    conversation,
 354→                    tools,
 355→                    &mut |text| {
 356→                        print!("{text}");
 357→                        io::stdout().flush().ok();
 358→                    },
 359→                )
 360→                .await;
 361→
 362→            match result {
 363→                Ok(r) => {
 364→                    api_result = Some(r);
 365→                    break;
 366→                }
 367→                Err(e) => {
 368→                    eprintln!("\n[error] API call failed: {e}");
 369→
 370→                    if classify_error(&e) == ErrorClass::Permanent {
 371→                        recover_conversation(conversation);
 372→                        stop_reason_str = "api_error";
 373→                        break;
 374→                    }
 375→
 376→                    // Transient error — retry if attempts remain
 377→                    if attempt >= MAX_RETRIES {
 378→                        eprintln!("[retry] Max retries ({MAX_RETRIES}) exhausted");
 379→                        recover_conversation(conversation);
 380→                        stop_reason_str = "api_error";
 381→                        break;
 382→                    }
 383→
 384→                    // Determine delay: retry-after header overrides backoff
 385→                    let delay = if let AgentError::HttpError {
 386→                        retry_after: Some(ra),
 387→                        ..
 388→                    } = &e
 389→                    {
 390→                        let capped = (*ra).min(RETRY_AFTER_CAP);
 391→                        eprintln!("[retry] Using retry-after: {capped}s");
 392→                        capped
 393→                    } else {
 394→                        BACKOFF_SCHEDULE[attempt]
 395→                    };
 396→
 397→                    if matches!(e, AgentError::StreamTransient(_)) {
 398→                        eprintln!("[retry] Retrying from beginning of response...");
 399→                    }
 400→
 401→                    eprintln!(
 402→                        "[retry] Attempt {}/{MAX_RETRIES}: {} — waiting {delay}s",
 403→                        attempt + 1,
 404→                        e
 405→                    );
 406→                    tokio::time::sleep(std::time::Duration::from_secs(delay)).await;
 407→                }
 408→            }
 409→        }
 410→
 411→        let (blocks, stop_reason, usage) = match api_result {
 412→            Some(r) => r,
 413→            None => break, // All retries failed or permanent error
 414→        };
 415→
 416→        // Update token tracking for next trim decision
 417→        last_input_tokens = usage.input_tokens;
 418→        total_tokens += usage.input_tokens + usage.output_tokens;
 419→
 420→        // Filter null-input tool_use blocks on MaxTokens truncation
 421→        let blocks = if stop_reason == StopReason::MaxTokens {
 422→            filter_null_input_tool_use(blocks)
 423→        } else {
 424→            blocks
 425→        };
 426→
 427→        // Add assistant response to conversation
 428→        let assistant_msg = Message {
 429→            role: "assistant".to_string(),
 430→            content: blocks.clone(),
 431→        };
 432→        conversation.push(assistant_msg.clone());
 433→        session.append_assistant_turn(&assistant_msg, &usage);
 434→
 435→        // --- Canonical three-way branch ---
 436→
 437→        // 1. EndTurn — normal completion
 438→        if stop_reason == StopReason::EndTurn {
 439→            println!();
 440→            stop_reason_str = "end_turn";
 441→            break;
 442→        }
 443→
 444→        // 2. MaxTokens — filter, then decide: continue, dispatch tools, or break
 445→        if stop_reason == StopReason::MaxTokens {
 446→            println!();
 447→
 448→            match classify_max_tokens(&blocks, continuation_count) {
 449→                MaxTokensAction::BreakEmpty => {
 450→                    eprintln!("[info] Empty response at max_tokens, breaking");
 451→                    stop_reason_str = "continuation_cap";
 452→                    break;
 453→                }
 454→                MaxTokensAction::DispatchTools => {
 455→                    // Valid tool_use blocks — fall through to tool dispatch below.
 456→                    // Do NOT increment continuation_count.
 457→                }
 458→                MaxTokensAction::Continue => {
 459→                    continuation_count += 1;
 460→                    eprintln!(
 461→                        "[continue] Response truncated at max_tokens, requesting continuation ({}/{})",
 462→                        continuation_count, MAX_CONTINUATIONS
 463→                    );
 464→
 465→                    let cont_msg = Message {
 466→                        role: "user".to_string(),
 467→                        content: vec![ContentBlock::Text {
 468→                            text: "Continue from where you left off.".to_string(),
 469→                        }],
 470→                    };
 471→                    conversation.push(cont_msg.clone());
 472→                    session.append_user_turn(&cont_msg);
 473→                    continue;
 474→                }
 475→                MaxTokensAction::BreakCapReached => {
 476→                    eprintln!("[continue] Max continuations reached, breaking");
 477→                    stop_reason_str = "continuation_cap";
 478→                    break;
 479→                }
 480→            }
 481→        }
 482→
 483→        // 3. Tool dispatch — runs for both ToolUse and MaxTokens-with-valid-tools
 484→        // Classify batch: if all tools are Pure, dispatch concurrently
 485→        let tool_uses: Vec<_> = blocks
 486→            .iter()
 487→            .filter_map(|b| {
 488→                if let ContentBlock::ToolUse { id, name, input } = b {
 489→                    Some((id.clone(), name.clone(), input.clone()))
 490→                } else {
 491→                    None
 492→                }
 493→            })
 494→            .collect();
 495→
 496→        let all_pure = !tool_uses.is_empty()
 497→            && tool_uses
 498→                .iter()
 499→                .all(|(_, name, _)| tool_effect(name) == ToolEffect::Pure);
 500→
 501→        let mut signal_break = false;
 502→        let mut threshold_tripped = false;
 503→        let mut threshold_reason = "";
 504→
 505→        let tool_results: Vec<ContentBlock> = if all_pure {
 506→            // Parallel path: all tools are pure (Read, Glob, Grep)
 507→            let batch_size = tool_uses.len();
 508→            let mut slots: Vec<Option<ContentBlock>> = vec![None; batch_size];
 509→            let mut blocked_flags: Vec<bool> = vec![false; batch_size];
 510→            let mut spawn_futures: Vec<(usize, tokio::task::JoinHandle<ContentBlock>)> = Vec::new();
 511→
 512→            for (i, (id, name, input)) in tool_uses.iter().enumerate() {
 513→                if input.is_null() {
 514→                    slots[i] = Some(ContentBlock::ToolResult {
 515→                        tool_use_id: id.clone(),
 516→                        content: "null input (truncated tool_use)".to_string(),
 517→                        is_error: Some(true),
 518→                    });
 519→                    continue;
 520→                }
 521→
 522→                // PreToolUse guard + observe
 523→                let pre_result = hooks.run_pre_tool_use(name, input, tool_iterations).await;
 524→
 525→                match pre_result {
 526→                    PreToolResult::Block { reason, .. } => {
 527→                        slots[i] = Some(ContentBlock::ToolResult {
 528→                            tool_use_id: id.clone(),
 529→                            content: reason,
 530→                            is_error: Some(true),
 531→                        });
 532→                        blocked_flags[i] = true;
 533→                        consecutive_block_count += 1;
 534→                        total_block_count += 1;
 535→
 536→                        if consecutive_block_count >= MAX_CONSECUTIVE_BLOCKS {
 537→                            eprintln!(
 538→                                "[hooks] Consecutive block limit ({MAX_CONSECUTIVE_BLOCKS}) reached"
 539→                            );
 540→                            threshold_tripped = true;
 541→                            threshold_reason = "block_limit_consecutive";
 542→                            break;
 543→                        }
 544→                        if total_block_count >= MAX_TOTAL_BLOCKS {
 545→                            eprintln!("[hooks] Total block limit ({MAX_TOTAL_BLOCKS}) reached");
 546→                            threshold_tripped = true;
 547→                            threshold_reason = "block_limit_total";
 548→                            break;
 549→                        }
 550→                    }
 551→                    PreToolResult::Allow => {
 552→                        consecutive_block_count = 0;
 553→
 554→                        if cli.verbose {
 555→                            eprintln!("\n[tool] {name}({})", truncate_json(input, 100));
 556→                        } else {
 557→                            eprintln!("\n[tool] {name}");
 558→                        }
 559→
 560→                        let id_owned = id.clone();
 561→                        let name_owned = name.clone();
 562→                        let input_owned = input.clone();
 563→
 564→                        let handle = tokio::task::spawn_blocking(move || {
 565→                            let result =
 566→                                dispatch_tool(&name_owned, &input_owned, &mut |_: &str| {});
 567→                            let (content, is_error) = match result {
 568→                                Ok(output) => (output, false),
 569→                                Err(err) => (err, true),
 570→                            };
 571→                            ContentBlock::ToolResult {
 572→                                tool_use_id: id_owned,
 573→                                content,
 574→                                is_error: if is_error { Some(true) } else { None },
 575→                            }
 576→                        });
 577→                        spawn_futures.push((i, handle));
 578→                    }
 579→                }
 580→            }
 581→
 582→            if threshold_tripped {
 583→                // Join already-spawned futures (avoid detaching JoinHandles)
 584→                let handles: Vec<_> = spawn_futures
 585→                    .into_iter()
 586→                    .map(|(idx, h)| async move {
 587→                        let result = h.await;
 588→                        (idx, result)
 589→                    })
 590→                    .collect();
 591→                let results = futures_util::future::join_all(handles).await;
 592→                for (idx, result) in results {
 593→                    slots[idx] = Some(match result {
 594→                        Ok(block) => block,
 595→                        Err(_) => ContentBlock::ToolResult {
 596→                            tool_use_id: tool_uses[idx].0.clone(),
 597→                            content: "tool panicked".to_string(),
 598→                            is_error: Some(true),
 599→                        },
 600→                    });
 601→                }
 602→                // Batch abandoned — conversation.pop() + break happens below
 603→                Vec::new() // placeholder, won't be used
 604→            } else {
 605→                // Normal path: join_all spawned futures
 606→                let handles: Vec<_> = spawn_futures
 607→                    .into_iter()
 608→                    .map(|(idx, h)| async move {
 609→                        let result = h.await;
 610→                        (idx, result)
 611→                    })
 612→                    .collect();
 613→                let results = futures_util::future::join_all(handles).await;
 614→                for (idx, result) in results {
 615→                    slots[idx] = Some(match result {
 616→                        Ok(block) => block,
 617→                        Err(_) => ContentBlock::ToolResult {
 618→                            tool_use_id: tool_uses[idx].0.clone(),
 619→                            content: "tool panicked".to_string(),
 620→                            is_error: Some(true),
 621→                        },
 622→                    });
 623→                }
 624→
 625→                // Post-dispatch logging
 626→                for slot in &slots {
 627→                    if let Some(ContentBlock::ToolResult {
 628→                        ref content,
 629→                        is_error,
 630→                        ..
 631→                    }) = slot
 632→                    {
 633→                        let is_err = is_error.unwrap_or(false);
 634→                        let display = format_tool_result_display(content, is_err, cli.verbose);
 635→                        eprintln!("{display}");
 636→                    }
 637→                }
 638→
 639→                // PostToolUse for non-blocked tools
 640→                for (i, (_, name, input)) in tool_uses.iter().enumerate() {
 641→                    if blocked_flags[i] {
 642→                        continue;
 643→                    }
 644→                    if let Some(ContentBlock::ToolResult {
 645→                        ref content,
 646→                        is_error,
 647→                        ..
 648→                    }) = slots[i]
 649→                    {
 650→                        let is_err = is_error.unwrap_or(false);
 651→                        let post_result = hooks
 652→                            .run_post_tool_use(name, input, content, is_err, tool_iterations)
 653→                            .await;
 654→                        if matches!(post_result, PostToolResult::Signal { .. }) {
 655→                            signal_break = true;
 656→                        }
 657→                    }
 658→                }
 659→
 660→                // Collect final results (unwrap all slots)
 661→                slots.into_iter().map(|s| s.unwrap()).collect()
 662→            }
 663→        } else {
 664→            // Sequential path: any Mutating tool in the batch
 665→            let mut tool_results: Vec<ContentBlock> = Vec::new();
 666→
 667→            for (id, name, input) in &tool_uses {
 668→                if input.is_null() {
 669→                    continue;
 670→                }
 671→
 672→                // PreToolUse guard + observe
 673→                let pre_result = hooks.run_pre_tool_use(name, input, tool_iterations).await;
 674→
 675→                match pre_result {
 676→                    PreToolResult::Block { reason, .. } => {
 677→                        tool_results.push(ContentBlock::ToolResult {
 678→                            tool_use_id: id.clone(),
 679→                            content: reason,
 680→                            is_error: Some(true),
 681→                        });
 682→                        consecutive_block_count += 1;
 683→                        total_block_count += 1;
 684→
 685→                        if consecutive_block_count >= MAX_CONSECUTIVE_BLOCKS {
 686→                            eprintln!(
 687→                                "[hooks] Consecutive block limit ({MAX_CONSECUTIVE_BLOCKS}) reached"
 688→                            );
 689→                            threshold_tripped = true;
 690→                            threshold_reason = "block_limit_consecutive";
 691→                            break;
 692→                        }
 693→                        if total_block_count >= MAX_TOTAL_BLOCKS {
 694→                            eprintln!("[hooks] Total block limit ({MAX_TOTAL_BLOCKS}) reached");
 695→                            threshold_tripped = true;
 696→                            threshold_reason = "block_limit_total";
 697→                            break;
 698→                        }
 699→                        continue;
 700→                    }
 701→                    PreToolResult::Allow => {
 702→                        consecutive_block_count = 0;
 703→                    }
 704→                }
 705→
 706→                if cli.verbose {
 707→                    eprintln!("\n[tool] {name}({})", truncate_json(input, 100));
 708→                } else {
 709→                    eprintln!("\n[tool] {name}");
 710→                }
 711→
 712→                let result = dispatch_tool(name, input, &mut |text| {
 713→                    if cli.verbose {
 714→                        eprint!("{text}");
 715→                    }
 716→                });
 717→
 718→                let (content, is_error) = match result {
 719→                    Ok(output) => {
 720→                        let display = format_tool_result_display(&output, false, cli.verbose);
 721→                        eprintln!("{display}");
 722→                        (output, false)
 723→                    }
 724→                    Err(err) => {
 725→                        let display = format_tool_result_display(&err, true, cli.verbose);
 726→                        eprintln!("{display}");
 727→                        (err, true)
 728→                    }
 729→                };
 730→
 731→                // PostToolUse
 732→                let post_result = hooks
 733→                    .run_post_tool_use(name, input, &content, is_error, tool_iterations)
 734→                    .await;
 735→                if matches!(post_result, PostToolResult::Signal { .. }) {
 736→                    signal_break = true;
 737→                }
 738→
 739→                tool_results.push(ContentBlock::ToolResult {
 740→                    tool_use_id: id.clone(),
 741→                    content,
 742→                    is_error: if is_error { Some(true) } else { None },
 743→                });
 744→            }
 745→
 746→            tool_results
 747→        };
 748→
 749→        // Block threshold takes unconditional precedence over signal_break
 750→        if threshold_tripped {
 751→            conversation.pop(); // Remove trailing Assistant message
 752→            stop_reason_str = threshold_reason;
 753→            break;
 754→        }
 755→
 756→        if tool_results.is_empty() {
 757→            break;
 758→        }
 759→
 760→        let tool_msg = Message {
 761→            role: "user".to_string(),
 762→            content: tool_results,
 763→        };
 764→        conversation.push(tool_msg.clone());
 765→        session.append_user_turn(&tool_msg);
 766→
 767→        tool_iterations += 1;
 768→
 769→        if signal_break {
 770→            stop_reason_str = "convergence_signal";
 771→            break;
 772→        }
 773→    }
 774→
 775→    // Fire stop hook
 776→    hooks
 777→        .run_stop(stop_reason_str, tool_iterations, total_tokens)
 778→        .await;
 779→}
