 781→fn truncate_json(value: &serde_json::Value, max_len: usize) -> String {
 782→    let s = value.to_string();
 783→    if s.len() <= max_len {
 784→        s
 785→    } else {
 786→        format!("{}...", &s[..s.floor_char_boundary(max_len)])
 787→    }
 788→}
 789→
 790→const MAX_CONTINUATIONS: usize = 3;
 791→
 792→/// Determine what to do after a MaxTokens stop_reason.
 793→/// Returns the action to take given the filtered content blocks and current continuation count.
 794→#[derive(Debug, PartialEq)]
 795→enum MaxTokensAction {
 796→    /// Response was empty (only placeholder) — break immediately
 797→    BreakEmpty,
 798→    /// Valid tool_use blocks present — fall through to tool dispatch
 799→    DispatchTools,
 800→    /// Text-only, under cap — inject continuation prompt
 801→    Continue,
 802→    /// Text-only, cap reached — break
 803→    BreakCapReached,
 804→}
 805→
 806→fn classify_max_tokens(blocks: &[ContentBlock], continuation_count: usize) -> MaxTokensAction {
 807→    // Check for empty response (only the "[Response truncated]" placeholder)
 808→    let is_empty = blocks.len() == 1
 809→        && matches!(&blocks[0], ContentBlock::Text { text } if text == "[Response truncated]");
 810→    if is_empty {
 811→        return MaxTokensAction::BreakEmpty;
 812→    }
 813→
 814→    let has_valid_tools = blocks
 815→        .iter()
 816→        .any(|b| matches!(b, ContentBlock::ToolUse { .. }));
 817→
 818→    if has_valid_tools {
 819→        MaxTokensAction::DispatchTools
 820→    } else if continuation_count < MAX_CONTINUATIONS {
 821→        MaxTokensAction::Continue
 822→    } else {
 823→        MaxTokensAction::BreakCapReached
 824→    }
 825→}
