1518→    fn total_block_never_resets_in_inner_loop() {
1519→        // Simulate: block, allow (resets consecutive only), block, block
1520→        let steps: &[bool] = &[false, true, false, false]; // true=allow, false=block
1521→        let mut total = 0usize;
1522→        let mut consecutive = 0usize;
1523→        for &is_allow in steps {
1524→            if is_allow {
1525→                consecutive = 0;
1526→            } else {
1527→                total += 1;
1528→                consecutive += 1;
1529→            }
1530→        }
