 123→    pub async fn run_pre_tool_use(
 124→        &self,
 125→        tool: &str,
 126→        input: &Value,
 127→        tool_iterations: usize,
 128→    ) -> PreToolResult {
 129→        // Guard phase
 130→        let guard_hooks: Vec<&HookConfig> = self
 131→            .hooks
 132→            .iter()
 133→            .filter(|h| h.event == "PreToolUse")
 134→            .filter(|h| {
 135→                let phase = h.phase.as_deref().unwrap_or("guard");
 136→                phase == "guard"
 137→            })
 138→            .filter(|h| matches_tool(h, tool))
 139→            .collect();
 140→
 141→        let mut blocked = false;
 142→        let mut blocked_by = String::new();
 143→        let mut block_reason = String::new();
 144→
 145→        for hook in &guard_hooks {
 146→            let hook_input = serde_json::json!({
 147→                "event": "PreToolUse",
 148→                "phase": "guard",
 149→                "tool": tool,
 150→                "input": input,
 151→                "tool_iterations": tool_iterations,
 152→                "cwd": self.cwd,
 153→            });
 154→
 155→            let timeout = hook.timeout_ms.unwrap_or(DEFAULT_TIMEOUT_MS);
 156→
 157→            match run_hook_subprocess(&hook.command, &hook_input, timeout).await {
 158→                Ok(stdout) => match serde_json::from_str::<GuardOutput>(&stdout) {
 159→                    Ok(output) => {
 160→                        if output.action == "block" {
 161→                            blocked = true;
 162→                            blocked_by = hook.command.clone();
 163→                            block_reason = output
 164→                                .reason
 165→                                .unwrap_or_else(|| "no reason provided".to_string());
 166→                            break;
 167→                        }
 168→                        // "allow" or anything else: continue to next guard
 169→                    }
 170→                    Err(_) => {
 171→                        blocked = true;
 172→                        blocked_by = hook.command.clone();
 173→                        block_reason = format!(
 174→                            "hook failed: {} returned invalid JSON (tool blocked by default)",
 175→                            hook.command
 176→                        );
 177→                        break;
 178→                    }
 179→                },
 180→                Err(HookError::Timeout(ms)) => {
 181→                    blocked = true;
 182→                    blocked_by = hook.command.clone();
 183→                    block_reason = format!(
 184→                        "hook failed: {} timed out after {ms}ms (tool blocked by default)",
 185→                        hook.command
 186→                    );
 187→                    break;
 188→                }
 189→                Err(HookError::NonZeroExit(code)) => {
 190→                    blocked = true;
 191→                    blocked_by = hook.command.clone();
 192→                    block_reason = format!(
 193→                        "hook failed: {} exited with code {code} (tool blocked by default)",
 194→                        hook.command
 195→                    );
 196→                    break;
 197→                }
 198→                Err(HookError::Spawn(msg)) => {
 199→                    blocked = true;
 200→                    blocked_by = hook.command.clone();
 201→                    block_reason = format!(
 202→                        "hook failed: {} spawn error: {msg} (tool blocked by default)",
 203→                        hook.command
 204→                    );
 205→                    break;
 206→                }
 207→            }
 208→        }
 209→
 210→        // Observe phase — always runs, with guard outcome context
 211→        let observe_hooks: Vec<&HookConfig> = self
 212→            .hooks
 213→            .iter()
 214→            .filter(|h| h.event == "PreToolUse")
 215→            .filter(|h| h.phase.as_deref() == Some("observe"))
 216→            .filter(|h| matches_tool(h, tool))
 217→            .collect();
 218→
 219→        for hook in &observe_hooks {
 220→            let mut hook_input = serde_json::json!({
 221→                "event": "PreToolUse",
 222→                "phase": "observe",
 223→                "tool": tool,
 224→                "input": input,
 225→                "blocked": blocked,
 226→                "tool_iterations": tool_iterations,
 227→                "cwd": self.cwd,
 228→            });
 229→
 230→            if blocked {
 231→                hook_input["blocked_by"] = Value::String(blocked_by.clone());
 232→                hook_input["block_reason"] = Value::String(block_reason.clone());
 233→            }
 234→
 235→            let timeout = hook.timeout_ms.unwrap_or(DEFAULT_TIMEOUT_MS);
 236→
 237→            // Fail-open: errors logged but don't affect outcome
 238→            match run_hook_subprocess(&hook.command, &hook_input, timeout).await {
 239→                Ok(_) => {} // Output ignored for observe hooks
 240→                Err(e) => {
 241→                    eprintln!("[hooks] Observe hook {} failed: {e}", hook.command);
 242→                }
 243→            }
 244→        }
 245→
 246→        if blocked {
 247→            let reason = if block_reason.starts_with("hook failed:") {
 248→                block_reason
 249→            } else {
 250→                format!("blocked by {blocked_by}: {block_reason}")
 251→            };
 252→            PreToolResult::Block { reason, blocked_by }
 253→        } else {
 254→            PreToolResult::Allow
 255→        }
 256→    }
