 342→    pub async fn run_stop(&self, reason: &str, tool_iterations: usize, total_tokens: u64) {
 343→        let matching_hooks: Vec<&HookConfig> =
 344→            self.hooks.iter().filter(|h| h.event == "Stop").collect();
 345→
 346→        for hook in &matching_hooks {
 347→            let hook_input = serde_json::json!({
 348→                "event": "Stop",
 349→                "reason": reason,
 350→                "tool_iterations": tool_iterations,
 351→                "total_tokens": total_tokens,
 352→                "cwd": self.cwd,
 353→            });
 354→
 355→            let timeout = hook.timeout_ms.unwrap_or(DEFAULT_STOP_TIMEOUT_MS);
 356→
 357→            // Fail-open
 358→            match run_hook_subprocess(&hook.command, &hook_input, timeout).await {
 359→                Ok(stdout) => {
 360→                    // Parse for logging only
 361→                    if let Ok(parsed) = serde_json::from_str::<Value>(&stdout) {
 362→                        let action = parsed["action"].as_str().unwrap_or("unknown");
 363→                        if action != "continue" {
 364→                            eprintln!(
 365→                                "[hooks] Stop hook {} returned unrecognized action: {action}",
 366→                                hook.command
 367→                            );
 368→                        }
 369→                    }
 370→                }
 371→                Err(e) => {
 372→                    eprintln!("[hooks] Stop hook {} failed: {e}", hook.command);
 373→                }
 374→            }
 375→        }
 376→
 377→        // Write final state to convergence.json
 378→        if let Err(e) = write_final_state(
 379→            reason,
 380→            tool_iterations,
 381→            total_tokens,
 382→            &self.convergence_dir,
 383→            &self.convergence_path,
 384→            &self.convergence_tmp,
 385→        ) {
 386→            eprintln!("[hooks] Warning: failed to write convergence final state: {e}");
 387→        }
 388→    }
